story-context.interfaces:
- **E2E Test Setup Pattern**:
  ```typescript
  describe('AuthController - Feature (e2e)', () => {
    let app: INestApplication;
    let prisma: PrismaService;
    let testDomainID: string;

    beforeAll(async () => {
      const moduleFixture: TestingModule = await Test.createTestingModule({
        imports: [AppModule],
      }).compile();

      app = moduleFixture.createNestApplication();
      const i18nService = app.get(I18nService);

      app.useGlobalInterceptors(new TransformResponseInterceptor(i18nService));
      app.useGlobalPipes(new ValidationPipe({ whitelist: true, forbidNonWhitelisted: true, transform: true }));

      prisma = app.get(PrismaService);
      testDomainID = generateTestDomainId();
      await seedTestData(prisma, testDomainID);
      await app.init();
    });

    afterAll(async () => {
      await cleanupTestData(prisma, testDomainID);
      await app.close();
    });

    afterEach(async () => {
      await prisma.user.deleteMany({ where: { domainID: testDomainID } });
    });
  });
  ```

- **Supertest HTTP Request Pattern**:
  ```typescript
  const response = await request(app.getHttpServer())
    .post('/auth/register')
    .send({ phoneNumber: '+905551234567', email: 'test@e2e.com', password: 'Test123!', firstName: 'Test', lastName: 'User' })
    .expect(201);

  expect(response.body).toEqual({
    success: true,
    status: 201,
    data: expect.objectContaining({ id: expect.any(String), email: 'test@e2e.com' }),
    message: expect.any(String)
  });
  ```

- **JWT Protected Route Testing**:
  ```typescript
  // Login to get token
  const loginRes = await request(app.getHttpServer())
    .post('/auth/login')
    .send({ email: 'test@e2e.com', password: 'Test123!' })
    .expect(200);

  const accessToken = loginRes.body.data.accessToken;

  // Access protected route with token
  await request(app.getHttpServer())
    .get('/users/profile')
    .set('Authorization', `Bearer ${accessToken}`)
    .expect(200);
  ```

- **Database State Verification**:
  ```typescript
  // After registration, verify user in database
  const user = await prisma.user.findUnique({ where: { email: 'test@e2e.com' } });
  expect(user).toBeDefined();
  expect(user.emailVerified).toBe(false);

  // After email verification, verify user.emailVerified updated
  const verifiedUser = await prisma.user.findUnique({ where: { email: 'test@e2e.com' } });
  expect(verifiedUser.emailVerified).toBe(true);
  ```

- **OTP Retrieval from Database**:
  ```typescript
  // Get OTP from database for email verification
  const otp = await prisma.oTPVerification.findFirst({
    where: { email: 'test@e2e.com' },
    orderBy: { createdAt: 'desc' }
  });
  expect(otp).toBeDefined();
  expect(otp.code).toBeDefined();
  ```
